const parsed = $('Parse AI Response').isExecuted
  ? ($('Parse AI Response').first().json || {})
  : ($input.first().json || {});

const tasksRaw = $items('Fetch Tasks in Cockpit').map(i => i.json);
const ticketsRaw = $items('Fetch Tickets in Cockpit').map(i => i.json);

const normalize = (v) => String(v || '')
  .toLowerCase()
  .normalize('NFD')
  .replace(/[\u0300-\u036f]/g, '')
  .replace(/[^a-z0-9\s]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

const collectObjects = (value, depth = 0, acc = []) => {
  if (depth > 8 || value == null) return acc;
  if (Array.isArray(value)) {
    for (const item of value) collectObjects(item, depth + 1, acc);
    return acc;
  }
  if (typeof value !== 'object') return acc;
  acc.push(value);
  for (const key of Object.keys(value)) collectObjects(value[key], depth + 1, acc);
  return acc;
};

const extractRecords = (value) => {
  const objs = collectObjects(value, 0, []);
  return objs.filter((obj) => obj && typeof obj === 'object' && !Array.isArray(obj) && ('id' in obj));
};

const uniqById = (arr) => {
  const seen = new Set();
  const out = [];
  for (const x of arr || []) {
    const key = String((x && x.id !== undefined) ? x.id : JSON.stringify(x));
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(x);
  }
  return out;
};

const ticketCategory = (c) => normalize(c);
const isTicketRow = (x) => {
  if (!x || x.id === undefined) return false;
  const cat = ticketCategory(x.category || '');
  if (['team record', 'client record', 'professional'].includes(cat)) return false;
  return !!(x.subject || x.description || x.project_id || x.project_name || x.client_name);
};

const isTaskRow = (x) => {
  if (!x || x.id === undefined) return false;
  const cat = ticketCategory(x.category || '');
  if (['team record', 'client record', 'professional'].includes(cat)) return false;
  return !!(x.title || x.description || x.project_id || x.project_name);
};

const tasks = uniqById(extractRecords(tasksRaw).filter(isTaskRow));
const tickets = uniqById(extractRecords(ticketsRaw).filter(isTicketRow));

const scope = normalize(parsed.entity?.scope || 'all');
const target = normalize(parsed.entity?.target || 'both');
const projectId = parsed.project_id || parsed.entity?.project_id || null;
const projectName = normalize(parsed.project_name || parsed.entity?.project_name || '');
const groupContext = parsed.groupContext || '';
const groupScope = normalize(parsed.entity?.group_scope || 'group');
const today = new Date().toISOString().slice(0, 10);

const isOpen = (s) => !['closed', 'completed', 'cancelled', 'resolved', 'done'].includes(normalize(s));
const dateOf = (obj) => {
  const d = obj?.due_date || obj?.deadline || obj?.date || obj?.created_date || obj?.created_at || obj?.updated_at || '';
  return String(d).slice(0, 10);
};

const projectMatch = (obj) => {
  const objProjectId = obj?.project_id != null ? String(obj.project_id) : '';
  const objProject = normalize(obj?.project_name || '');
  const objClient = normalize(obj?.client_name || '');

  if (projectId != null && String(projectId) !== '') {
    return objProjectId === String(projectId);
  }

  if (projectName) {
    return objProject.includes(projectName) || objClient.includes(projectName);
  }

  if (groupScope === 'global') return true;

  if (groupContext === 'garlic') return /garlic|gnl/.test(objProject + ' ' + objClient);
  if (groupContext === 'ernesto') return /ernesto/.test(objProject + ' ' + objClient);
  if (groupContext === 'angelfly') return /angel\s*fly|cockpit/.test(objProject + ' ' + objClient);

  return true;
};

const scoped = (arr, kind) => arr.filter(x => {
  if (!projectMatch(x)) return false;
  if (scope === 'today') return dateOf(x) === today;
  if (scope === 'open') return isOpen(kind === 'ticket' ? (x.status || 'open') : (x.status || 'assigned'));
  return true;
});

const fTasks = scoped(tasks, 'task');
const fTickets = scoped(tickets, 'ticket');

const top = (arr, fieldName) => arr.slice(0, 10).map((x, idx) => {
  const name = x[fieldName] || x.title || x.subject || '(sem título)';
  const st = x.status || '-';
  const pr = x.priority || '-';
  const assignee = x.assigned_to_name || '';
  const dl = x.deadline || x.due_date || '';
  let line = String(idx + 1) + '. ' + name + ' [' + st + '/' + pr + ']';
  if (assignee) line += ' 👤 ' + assignee;
  if (dl) line += ' 📅 ' + dl;
  return line;
});

let text = '📊 Relatório Cockpit';
if (parsed.project_name) text += ' - ' + parsed.project_name;
text += '\nFiltro: ' + scope + ' | ' + target;

const hasApiError = tasksRaw.some(x => x && x.error) || ticketsRaw.some(x => x && x.error);
if (hasApiError && fTasks.length === 0 && fTickets.length === 0) {
  text = '⚠️ Erro ao consultar a API do Cockpit.\nNão foi possível obter os dados no momento.';
} else {
  if (target === 'tasks' || target === 'both') {
    text += '\n\n🧩 Tasks (' + fTasks.length + ')';
    if (fTasks.length) text += '\n' + top(fTasks, 'title').join('\n');
  }

  if (target === 'tickets' || target === 'both') {
    text += '\n\n🎫 Tickets (' + fTickets.length + ')';
    if (fTickets.length) text += '\n' + top(fTickets, 'subject').join('\n');
  }

  if ((target === 'tasks' && fTasks.length === 0) || (target === 'tickets' && fTickets.length === 0) || (target === 'both' && fTasks.length === 0 && fTickets.length === 0)) {
    text += '\n\nNenhum item encontrado com esse filtro.';
  }
}

return [{ json: { ...parsed, reply: text, waChatId: parsed.waChatId || parsed.chatId } }];

